namespace OpenTelemetry.SemanticConventions.SourceGeneration;

/// <summary>
/// Immutable, value-equality array used as a pipeline-cacheable input/output
/// for Roslyn incremental generators. Elements must themselves have value
/// equality (records, primitives) for the equality contract to hold.
/// </summary>
internal readonly struct EquatableArray<T> : IEquatable<EquatableArray<T>>, IReadOnlyList<T>
    where T : IEquatable<T>
{
    public static readonly EquatableArray<T> Empty = new(Array.Empty<T>());

    private readonly T[] _items;

    public EquatableArray(T[] items)
