/// <summary>
/// Filters out null entries from an incremental values provider so the
/// downstream pipeline can rely on non-null values without separate null
/// checks at every consumer. Mirrors the convenience helper that
/// IIncrementalGenerator pipelines commonly inline.
/// </summary>
internal static class IncrementalValuesProviderExtensions
{
    public static IncrementalValuesProvider<T> WhereNotNull<T>(
        this IncrementalValuesProvider<T?> source)
        where T : struct =>
        source.Where(static x => x.HasValue).Select(static (x, _) => x!.Value);
}

/// <summary>
/// Pair of (file hint name, source text) returned by emitters. Value-equality
/// so the generator pipeline can cache it.
/// </summary>
internal readonly record struct FileWithName(string Name, string Text)
{
    public static FileWithName Empty => new(string.Empty, string.Empty);

    public bool IsEmpty => string.IsNullOrEmpty(Name) || string.IsNullOrEmpty(Text);
}
